-- =============================================================================
-- Webnua backend — Phase 4 · seed the builder family.
--
-- Loads the website + funnel content the frontend stub layer
-- (lib/website/data-stub.tsx + lib/funnel/data-stub.tsx) carries into the
-- live tables, so the Phase 4 read-wiring has real rows to read:
--
--   Voltline   → 3-page website (Home/About/Contact populated, Services
--                empty) + a draft identical to the published version, plus
--                the 3-step "$99 emergency call-out" funnel.
--   FreshHome  → 4-page website, fully published, draft ahead of published
--                (home hero copy edits pending).
--   KeyHero    → 1-page website, draft only, never published.
--   NeatWorks  → no website / funnel (agency-roster empty state).
--
-- version_status snapshots are the app-shaped content tree stored verbatim
-- (Option B — pages/steps/sections live inside the snapshot JSONB). Drafts
-- that match their published version are derived (insert..select) rather
-- than re-storing the tree; the FreshHome draft is the published snapshot
-- with the home hero copy patched via jsonb_set.
-- Idempotent: clears the builder family first, so re-running is safe.
-- =============================================================================

-- Clear any pre-seed placeholder rows. Order respects the circular FKs:
-- null the version pointers before deleting the versions they reference.
update public.websites set draft_version_id = null, published_version_id = null;
update public.funnels  set draft_version_id = null, published_version_id = null;
delete from public.website_versions;
delete from public.funnel_versions;
delete from public.websites;
delete from public.funnels;

